module top_module(
  input [2:0] a,
  output reg [7:0] error_out
);always @(*)
  begin
    case(a)
      3'b000: error_out = 8'b00000001;
      3'b001: error_out = 8'b00000010;
      3'b010: error_out = 8'b00000100;
      3'b011: error_out = 8'b00001000;
      3'b100: error_out = 8'b00010000;
      3'b101: error_out = 8'b00100000;
      3'b110: error_out = 8'b01000000;
      3'b111: error_out = 8'b10000000;
      default: error_out = 8'b11111111;
    endcase
  end

endmodule
